    bits: Uint8Array;
    length: number;
    constructor({ length, buffer, leftToRightIndexing, littleEndianBits }?: BitstringType);
    set(position: number, on: boolean): void;
    get(position: number): boolean;
    encodeBits(): Promise<string>;
